import { prisma } from "@/src/lib/prisma";
import { analyzeWebsiteText } from "@/src/lib/anthropic";
import { redirect } from "next/navigation";

function stripHtml(html: string) {
    return html
        .replace(/<script[\s\S]*?<\/script>/gi, "")
        .replace(/<style[\s\S]*?<\/style>/gi, "")
        .replace(/<[^>]+>/g, " ")
        .replace(/\s+/g, " ")
        .trim();
}

function getErrorMessage(error: unknown) {
    if (error instanceof Error) return error.message;
    if (typeof error === "string") return error;

    try {
        return JSON.stringify(error);
    } catch {
        return "Unknown error";
    }
}

function extractJsonObject(text: string) {
    const trimmed = text.trim();

    try {
        return JSON.parse(trimmed);
    } catch { }

    const start = trimmed.indexOf("{");
    const end = trimmed.lastIndexOf("}");

    if (start !== -1 && end !== -1 && end > start) {
        const possible = trimmed.slice(start, end + 1);

        try {
            return JSON.parse(possible);
        } catch { }
    }

    return null;
}

function normalizeAdCount(value: string | null | undefined) {
    const parsed = Number(value);

    if (!Number.isFinite(parsed)) return "6";
    if (parsed < 1) return "1";
    if (parsed > 1000) return "1000";

    return String(Math.floor(parsed));
}

function validateAds(parsed: any, requestedCount: number) {
    if (!parsed || typeof parsed !== "object") {
        throw new Error("Claude did not return a valid JSON object.");
    }

    if (!Array.isArray(parsed.ads)) {
        throw new Error("Claude response is missing the ads array.");
    }

    if (parsed.ads.length !== requestedCount) {
        throw new Error(
            `Claude returned ${parsed.ads.length} ads but ${requestedCount} were requested.`
        );
    }

    parsed.ads.forEach((ad: any, index: number) => {
        const adNum = index + 1;

        if (!ad || typeof ad !== "object") {
            throw new Error(`Ad ${adNum} is not a valid object.`);
        }

        const requiredFields = [
            "angle",
            "audience",
            "format",
            "style",
            "referenceImageGuidance",
            "scenePrompt",
            "textOverlayTop",
            "cta",
            "typographyDirection",
            "editedPrompt",
        ];

        for (const field of requiredFields) {
            const value = ad[field];
            if (typeof value !== "string" || !value.trim()) {
                throw new Error(`Ad ${adNum} is missing required field: ${field}`);
            }
        }
    });

    return parsed.ads;
}

async function createJob(formData: FormData) {
    "use server";

    const url = formData.get("url")?.toString().trim();
    const campaignType =
        formData.get("campaignType")?.toString().trim() || "product";
    const platform = formData.get("platform")?.toString().trim() || "Meta";
    const funnelStage = formData.get("funnelStage")?.toString().trim() || "Mix";
    const formatRatio =
        formData.get("formatRatio")?.toString().trim() ||
        "70% 9:16 / 30% 1080x1080";
    const primaryAngles =
        formData.get("primaryAngles")?.toString().trim() ||
        "Problem/Solution, Lifestyle, Urgency";
    const testimonialUsage =
        formData.get("testimonialUsage")?.toString().trim() || "Mix";
    const ctaStyle = formData.get("ctaStyle")?.toString().trim() || "Mix";
    const visualStyle = formData.get("visualStyle")?.toString().trim() || "Mix";
    const numberOfAds = normalizeAdCount(
        formData.get("numberOfAds")?.toString().trim()
    );
    const requestedCount = Number(numberOfAds);
    const referenceImageTypes =
        formData.get("referenceImageTypes")?.toString().trim() || "Product only";

    if (!url) {
        throw new Error("URL is required");
    }

    const response = await fetch(url, {
        method: "GET",
        headers: {
            "User-Agent": "Mozilla/5.0",
        },
        cache: "no-store",
    });

    const html = await response.text();
    const rawText = stripHtml(html).slice(0, 15000);

    let claudeOutput = "";
    let status = "processed";

    try {
        claudeOutput = await analyzeWebsiteText({
            rawText,
            campaignType,
            platform,
            funnelStage,
            formatRatio,
            primaryAngles,
            testimonialUsage,
            ctaStyle,
            visualStyle,
            numberOfAds,
            referenceImageTypes,
        });
    } catch (error) {
        const message = getErrorMessage(error);
        claudeOutput = JSON.stringify(
            {
                summary: {},
                targetAudience: { segments: [] },
                productsServices: {},
                styleDirection: { styles: [] },
                otherFields: {
                    bestTestimonials: [],
                    ctaVariations: [],
                    urgencyHooks: [],
                    seasonalAngles: [],
                    platformNotes: [],
                },
                ads: [],
                error: message,
            },
            null,
            2
        );
        status = "claude_error";
    }

    const job = await prisma.job.create({
        data: {
            url,
            campaignType,
            rawText,
            claudeOutput,
            status,
            platform,
            funnelStage,
            formatRatio,
            primaryAngles,
            testimonialUsage,
            ctaStyle,
            visualStyle,
            numberOfAds,
            referenceImageTypes,
        },
    });

    try {
        const parsed = extractJsonObject(claudeOutput);
        const ads = validateAds(parsed, requestedCount);

        await prisma.ad.createMany({
            data: ads.map((ad: any, index: number) => ({
                jobId: job.id,
                adNumber: index + 1,
                title: ad.angle || `Ad ${index + 1}`,
                sourceBlock: JSON.stringify(ad, null, 2),
                editedPrompt: ad.editedPrompt || ad.scenePrompt || "",
                status: "ready",
            })),
        });

        redirect(`/jobs/${job.id}?ad=1`);
    } catch (error) {
        const message = getErrorMessage(error);

        await prisma.job.update({
            where: { id: job.id },
            data: {
                status: "ad_parse_error",
                claudeOutput: `${claudeOutput}

VALIDATION ERROR:
${message}`,
            },
        });

        redirect(`/jobs/${job.id}`);
    }
}

